#include <stdio.h>
#include <string.h>
#include <math.h>
#include <stdlib.h>

struct Node
{
    int starting;
    int no_of_edges;
};

__global__ void bfs_update_kernel(int no_of_nodes, bool *h_graph_mask, bool *h_updating_graph_mask, 
                                   bool *h_graph_visited, Node *h_graph_nodes, int *h_graph_edges, 
                                   int *h_cost)
{
    int tid = threadIdx.x + blockIdx.x * blockDim.x;
    if (tid < no_of_nodes) {
        if (h_graph_mask[tid] == true) { 
            h_graph_mask[tid] = false;
            for(int i = h_graph_nodes[tid].starting; i < (h_graph_nodes[tid].no_of_edges + h_graph_nodes[tid].starting); i++)
            {
                int id = h_graph_edges[i];
                if(!h_graph_visited[id])
                {
                    h_cost[id] = h_cost[tid] + 1;
                    h_updating_graph_mask[id] = true;
                }
            }
        }
    }
}

__global__ void bfs_mark_kernel(int no_of_nodes, bool *h_graph_mask, bool *h_updating_graph_mask, 
                                 bool *h_graph_visited, int *stop_flag)
{
    int tid = threadIdx.x + blockIdx.x * blockDim.x;
    if (tid < no_of_nodes) {
        if (h_updating_graph_mask[tid] == true){
            h_graph_mask[tid] = true;
            h_graph_visited[tid] = true;
            *stop_flag = 1;
            h_updating_graph_mask[tid] = false;
        }
    }
}

